\begin{lemma}
[E3 ratio core --- the localised minor-ratio identity (coverage)]
  \label{lem:gr_existence_lift_transitionPreMap_minorDet_mul}
  \lean{AlgebraicGeometry.Grassmannian.existence_lift_transitionPreMap_minorDet_mul}
  \uses{lem:gr_transitionPreMap_minorDet_mul, lem:mathlib_away_lift}
  \textit{Source: [Nitsure] \S1, the displayed minor-ratio of the Properness step; the reusable
  algebraic core of \cref{lem:gr_existence_factor_through_valuation_ring} (it does not touch the
  cofactor sub-step).}
  Let \(f' : R^I_J \to K\) be the away-localisation lift (\cref{lem:mathlib_away_lift}) of
  \(f : R^I \to K\) along \(P^I_J\). For every size-\(d\) subset \(K'\),
  \[
    f'\bigl(\tilde\theta_{I,J}(P^J_{K'})\bigr)\cdot f(P^I_J) \;=\; f(P^I_{K'}),
  \]
  i.e.\ \(g(P^J_{K'})\cdot f(P^I_J) = f(P^I_{K'})\) with \(g := f' \circ \tilde\theta_{I,J}\).
\end{lemma}
\begin{proof}
  \uses{lem:gr_transitionPreMap_minorDet_mul, lem:mathlib_away_lift}
  Apply \(f'\) (via \(\mathrm{congrArg}\) and \(\mathrm{map\_mul}\)) to the ring-level identity
  \cref{lem:gr_transitionPreMap_minorDet_mul}; \(\mathrm{IsLocalization.Away.lift\_eq}\) collapses the
  two \(\mathrm{algebraMap}\)-images to \(f(P^I_J)\) and \(f(P^I_{K'})\), yielding the displayed
  equation.
\end{proof}

